package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.qualification.QualificationRequirementApplicationService;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1/qualification-requirements")public class QualificationRequirementController {private final QualificationRequirementApplicationService service;private final CommandContextFactory contexts;public QualificationRequirementController(QualificationRequirementApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping public ApiResponse<List<QualificationRequirementApplicationService.View>> list(HttpServletRequest r){return ApiResponse.success(service.list(),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<Long> create(@Valid @RequestBody Save b,HttpServletRequest r,Authentication a){return ApiResponse.success(service.create(b.supplierType(),b.categoryId(),b.qualificationType(),b.mandatory(),contexts.create(r,a)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PutMapping("/{id}")public ApiResponse<Void> update(@PathVariable long id,@Valid @RequestBody Update b,HttpServletRequest r,Authentication a){service.update(id,b.version(),b.supplierType(),b.categoryId(),b.qualificationType(),b.mandatory(),b.status(),contexts.create(r,a));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Save(String supplierType,Long categoryId,@NotBlank String qualificationType,boolean mandatory){}public record Update(@PositiveOrZero int version,String supplierType,Long categoryId,@NotBlank String qualificationType,boolean mandatory,@Min(1)@Max(2)int status){}}
